  const invalid = (fieldCounts[f.code] || {}).invalid || 0;
  checks.push({ name: f.label + ' (Productos)', passed: total - missed - invalid, failed: missed + invalid, warnings: 0, critical: true });
}

for (const f of OFFERS_RED) {
  const missed = (fieldCounts['offer_' + f.code] || {}).missing || 0;
  checks.push({ name: f.label + ' (Ofertas)', passed: total - missed, failed: 0, warnings: missed, critical: false });
}

for (const f of CAMPAIGN_FIELDS) {
  let campMissing = 0;
  for (const p of products) { const m = mapInputRow(p); if (!String(m[f.code] || '').trim()) campMissing++; }
  checks.push({ name: f.label + ' (Campaña)', passed: total - campMissing, failed: 0, warnings: campMissing, critical: false });
}

const summary = { total, valid: valid.length, withErrors: errors.length, withWarnings: warnings.length, checks };
const msg = isPT ? valid.length + ' de ' + total + ' produtos válidos para Sprinter/Mirakl' : valid.length + ' de ' + total + ' productos válidos para Sprinter/Mirakl';
return [{ json: { status: 'completed', summary, errors: errors.slice(0, 50), warnings: warnings.slice(0, 50), message: msg } }];
